import { FunctionComponent, VNode } from 'preact';
import { HTMLAttributes } from 'preact/compat';
import {
  Skeleton,
  SkeletonRow,
  ContentGrid,
} from '@adobe-commerce/elsie/components';
import { classes, VComponent } from '@adobe-commerce/elsie/lib';

import '@/recommendations/components/ProductList/ProductList.css';

export interface ProductListProps
  extends HTMLAttributes<HTMLDivElement>,
    Omit<HTMLAttributes<HTMLDivElement>, 'loading'> {
  heading?: VNode | null;
  products?: VNode | null;
  loading?: boolean;
}

export const ProductList: FunctionComponent<ProductListProps> = ({
  className,
  children,
  heading,
  products = null,
  loading = true,
  ...props
}) => {
  return (
    <section
      {...props}
      role="region"
      aria-label="Product recommendations"
      className={classes([
        'recommendations-product-list',
        className,
        ['recommendations-product-list--empty', !products],
      ])}
    >
      {loading ? (
        <ProductListSkeleton />
      ) : (
        <>
          {heading && (
            <VComponent
              node={heading}
              className="recommendations-product-list__heading"
            />
          )}
          <ContentGrid
            className="recommendations-product-list__content"
            data-testid="recommendations-product-list__content"
            maxColumns={0}
            columnWidth="minmax(240px, 1fr)"
          >
            {products}
          </ContentGrid>
        </>
      )}
    </section>
  );
};

const ProductListSkeleton: FunctionComponent = () => {
  return (
    <Skeleton
      data-testid="recommendations-product-list-skeleton"
      className="recommendations-product-list-skeleton"
      rowGap="medium"
    >
      {[...Array(2)].map((_, i) => (
        <SkeletonRow
          key={i}
          variant="row"
          size="large"
          fullWidth
          lines={2}
          multilineGap="small"
        />
      ))}
    </Skeleton>
  );
};
